-- =============================================
-- UPDATE EXISTING EXERCISES WITH IMAGES
-- Source: github.com/yuhonas/free-exercise-db
-- Images: position 0 (start) and position 1 (end)
-- We'll store 0.jpg as thumbnail and use a special URL format
-- to indicate animation: "thumbnail|alt" so the component can split
UPDATE public.exercises SET thumbnail_url = 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/3_4_Sit-Up/0.jpg', video_url = 'https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/3_4_Sit-Up/1.jpg' WHERE name = '3/4 Sit-Up' AND is_global = TRUE;
